// S-polynomial of f and g: S = (L/LT(f))*f - (L/LT(g))*g with L = lcm of
// the two leading monomials, each part scaled monic.  Cancels the leading
// terms.  Fresh result slot (caller owns), or SENT.  Uses GROEBNER_SP_*.
// GROEBNER_SPOLY_STATUS records the failure reason (NOSESS / BAD / INV / FULL)
// so callers can distinguish storage-overflow from field-invertibility.
fn gb_spoly(f: u32, g: u32) -> u32 @export {
    if GROEBNER_SESS != 1u8 { GROEBNER_SPOLY_STATUS = GROEBNER_E_NOSESS ; return GROEBNER_SENT }
    if gb_is_zero(f) == 1u8 { GROEBNER_SPOLY_STATUS = GROEBNER_E_BAD ; return GROEBNER_SENT }
    if gb_is_zero(g) == 1u8 { GROEBNER_SPOLY_STATUS = GROEBNER_E_BAD ; return GROEBNER_SENT }
    let arena : u64 = GROEBNER_ARENA
    let p : u64 = GROEBNER_MOD_P
    let nv : u32 = GROEBNER_NVARS
    let fst : u32 = GROEBNER_PL_START[f]
    let gst : u32 = GROEBNER_PL_START[g]
    let fpe : *u32 = gb_term_exp_ptr(fst)
    let gpe : *u32 = gb_term_exp_ptr(gst)
    let fe : *u32 = &GROEBNER_SP_FE[0u32]
    let ge : *u32 = &GROEBNER_SP_GE[0u32]
    let ll : *u32 = &GROEBNER_SP_LL[0u32]
    let df : *u32 = &GROEBNER_SP_DF[0u32]
    let dg : *u32 = &GROEBNER_SP_DG[0u32]
    let mut i : u32 = 0u32
    while i < nv {
        let ix : u64 = (i as u64) & GROEBNER_U32MASK
        fe[ix] = fpe[ix]
        ge[ix] = gpe[ix]
        i = i + 1u32
    }
    gb_lcm(fe, ge, ll)
    let mut k : u32 = 0u32
    while k < nv {
        let kx : u64 = (k as u64) & GROEBNER_U32MASK
        df[kx] = ll[kx] - fe[kx]
        dg[kx] = ll[kx] - ge[kx]
        k = k + 1u32
    }
    let fc : u64 = GROEBNER_TERM_COEFF[fst]
    let gc : u64 = GROEBNER_TERM_COEFF[gst]
    let finv : u64 = gfp_inv(arena, fc, p)
    if finv == 0u64 { GROEBNER_SPOLY_STATUS = GROEBNER_E_INV ; return GROEBNER_SENT }
    let ginv : u64 = gfp_inv(arena, gc, p)
    if ginv == 0u64 { bigint_drop(finv) ; GROEBNER_SPOLY_STATUS = GROEBNER_E_INV ; return GROEBNER_SENT }
    let part_f : u32 = gb_mul_term(f, finv, df)
    bigint_drop(finv)
    if part_f == GROEBNER_SENT { bigint_drop(ginv) ; GROEBNER_SPOLY_STATUS = GROEBNER_E_FULL ; return GROEBNER_SENT }
    let part_g : u32 = gb_mul_term(g, ginv, dg)
    bigint_drop(ginv)
    if part_g == GROEBNER_SENT { gb_drop_poly(part_f) ; GROEBNER_SPOLY_STATUS = GROEBNER_E_FULL ; return GROEBNER_SENT }
    let out : u32 = gb_sub_new(part_f, part_g)
    gb_drop_poly(part_g)
    gb_drop_poly(part_f)
    if out == GROEBNER_SENT { GROEBNER_SPOLY_STATUS = GROEBNER_E_FULL ; return GROEBNER_SENT }
    GROEBNER_SPOLY_STATUS = GROEBNER_OK
    return out
}

/* the function the netlist computes: pack its output over all 2^n input assignments into a u64.
 * REQUIRES n <= 6: a u64 holds exactly 2^6=64 bits; n=7 needs 128 bits which does not fit.
 * Returns 0u64 (the all-false function) immediately for n>6 -- a safe sentinel that no
 * well-formed optimizer result can equal (all outputs zero means the output is constant false,
 * so the caller's equivalence check will correctly reject it as non-equivalent to a non-trivial
 * circuit).  This also prevents the x86 shlq %cl wrapping defect: cl&63 maps 64->0, so
 * `1u64 << 64` silently equals 1, producing a wrong truth table bit for rows 64..127. */
fn hdl_opt_truth_table(out: u32, n: u32) -> u64 @export {
    if n > 6u32 { return 0u64 }

fn hkdf_sha256_extract(salt: *u8, salt_len: u64, ikm: *u8, ikm_len: u64) -> i32 @export {
    /* PRK = HMAC-SHA256(salt, IKM) */
    let mut k : *u8 = salt
    let mut k_len : u64 = salt_len
    if k_len == 0u64 {
        k = (&HKDF_WORK_ZERO) as u64 as *u8
        k_len = 32u64
    }
    let he : i32 = hmac_sha256(k, k_len, ikm, ikm_len)
    if he != HKDF_OK { return HKDF_E_HMAC }
    let te : i32 = hmac_sha256_tag((&HKDF_WORK_PRK) as u64 as *u8)
    if te != HKDF_OK { return HKDF_E_HMAC }
    HKDF_PRK_READY = 1u8
    return HKDF_OK
}

