Concretely for the groebner NEGATIVE KAT (insert before `return 99u64` in gb_selftest):

    // ---- KAT 5: FULL mis-typed as INV -- proves GROEBNER_SPOLY_STATUS fixes the error code ----
    // Exhaust the term bump to force E_FULL inside gb_spoly -> gb_buch_step.
    // We saturate GROEBNER_TERM_USED to GROEBNER_MAX_TERMS - 1 by appending
    // to a scratch poly until one more append would tip over.
    if gb_init(1u32) != GROEBNER_OK { return 80u64 }
    if gb_begin(arena, p) != GROEBNER_OK { return 81u64 }
    let sc5 : u32 = gb_new_poly()
    if sc5 == GROEBNER_SENT { return 82u64 }
    // Fill term table to within 1 slot of capacity so the NEXT append inside
    // gb_mul_term (called by gb_spoly) hits E_FULL.
    GROEBNER_TERM_USED = GROEBNER_MAX_TERMS - 1u32   // direct module-scope write (selftest privilege)
    // Build two non-coprime polys: f = x+1, g = x+2 (share var x -> S-poly triggers)
    let f5 : u32 = gb_new_poly()
    if f5 == GROEBNER_SENT { return 83u64 }
    gb_kat_set2(1u32, 0u32)
    gb_append_term(f5, bigint_from_u64(arena, 1u64), &GROEBNER_KAT_EXPS[0u32])
    gb_kat_set2(0u32, 0u32)
    gb_append_term(f5, bigint_from_u64(arena, 1u64), &GROEBNER_KAT_EXPS[0u32])
    gb_normalize(f5)
    // Now GROEBNER_TERM_USED is well above capacity -> gb_spoly -> gb_mul_term returns SENT -> E_FULL
    GROEBNER_KAT_BASIS[0u64] = f5
    let res5 : i32 = gb_buchberger(&GROEBNER_KAT_BASIS[0u32], 1u32, &GROEBNER_KAT_OUTB[0u32], &GROEBNER_KAT_OUTN[0u32])
    // Must be E_FULL, NOT E_INV (that was the bug before this fix)
    if res5 != GROEBNER_E_FULL { return 84u64 }

NOTE: The direct write `GROEBNER_TERM_USED = GROEBNER_MAX_TERMS - 1u32` is only valid inside gb_selftest which has module-scope access (same module). The selftest already uses this privilege for GROEBNER_KAT_BASIS[0u64] direct writes. Since the term bump is now near capacity, the 2 appended terms (lines above) may push it over -- adjust the logic so that the TERM_USED is set such that gb_mul_term (which needs NVARS*term entries) hits the cap. For nvars=1, each term consumes 1 exp slot; set GROEBNER_TERM_USED = GROEBNER_MAX_TERMS - 1u32 and GROEBNER_EXP_USED = GROEBNER_EXP_AREA - 1u64 to guarantee both the term and exp caps are hit.
